-- Prompt 36: privacy query enforcement and separate consent/account workflows.
begin;set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
select public.save_profile_privacy('Private Cruxer','private','private',false,true);
do $$begin if exists(select 1 from public.search_gym_content('30000000-0000-4000-8000-000000000001','Private Cruxer',20)where result_kind='member')then raise exception'Private profile appeared in search';end if;if not exists(select 1 from public.consent_records where profile_id=auth.uid()and consent_type='marketing'and granted)then raise exception'Marketing consent was not recorded separately';end if;end$$;
select public.save_profile_privacy('Public Cruxer','gym','gym',true,false);do $$begin if not exists(select 1 from public.search_gym_content('30000000-0000-4000-8000-000000000001','Public Cruxer',20)where result_kind='member'and title='Public Cruxer')then raise exception'Opted-in public name was not searchable';end if;end$$;
select public.request_account_deletion('Please remove ordinary account content');do $$begin if not exists(select 1 from public.account_deletion_requests where profile_id=auth.uid()and status='requested')then raise exception'Deletion request was not created';end if;end$$;
do $$begin begin perform public.export_member_subject_data('30000000-0000-4000-8000-000000000001',auth.uid());raise exception'Member used owner subject export';exception when insufficient_privilege then null;end;end$$;select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);do $$declare exported jsonb;begin exported:=public.export_member_subject_data('30000000-0000-4000-8000-000000000001','10000000-0000-4000-8000-000000000004');if exported#>>'{profile,id}'<>'10000000-0000-4000-8000-000000000004'then raise exception'Owner subject export was incorrectly scoped';end if;end$$;select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
select public.deactivate_my_account('Taking a break');set local role service_role;do $$begin if not exists(select 1 from public.profiles where id='10000000-0000-4000-8000-000000000004'and deactivated_at is not null)or exists(select 1 from public.gym_memberships where profile_id='10000000-0000-4000-8000-000000000004'and status='active')then raise exception'Deactivation did not block active access';end if;if not exists(select 1 from public.audit_logs where action='privacy.account.deactivated')then raise exception'Deactivation was not audited';end if;end$$;rollback;
